# Replace argmax with sampling from the top q-quantile of a base
# distribution. Avoids the degenerate tail where the proxy and true
# preference diverge most.

Q = 0.05                                            # top 5% quantile
SATISFICE = 0.85                                    # 'good enough' threshold

function quantilizer_choose(candidates, base_dist, inferred_reward):
    scored = [(a, inferred_reward.evaluate(a), base_dist.prob(a))
              for a in candidates]
    cutoff = quantile([s for (_, s, _) in scored], q=1 - Q)
    top    = [(a, s, p) for (a, s, p) in scored if s >= cutoff]
    # Sample from the top q-quantile weighted by the BASE distribution,
    # not by reward. Taylor's bound: expected cost under any bounded
    # utility is at most 1/Q times the base distribution's cost.
    return weighted_sample(top, weights=[p for (_, _, p) in top])

function satisficing_choose(candidates, inferred_reward):
    for a in candidates:                            # in agent's natural order
        if inferred_reward.evaluate(a) >= SATISFICE:
            return a                                # first good-enough wins
    return argmax(candidates, key=inferred_reward.evaluate)

function pick_action(state):
    candidates = generate_candidate_actions(state)
    if state.mode == "quantilize":
        return quantilizer_choose(candidates, base_dist=state.prior,
                                  inferred_reward=state.reward)
    return satisficing_choose(candidates, inferred_reward=state.reward)

