        if not schema.validate(sub_output, context.expected_schema):
            return {verdict: "reject", reason: "schema", code: "SCHEMA_INVALID"}
        verdict = policy.check(sub_output, context.policy_bundle)
        if not verdict.ok:
            return {verdict: "reject", reason: "policy", code: verdict.rule_id}
        if context.allow_list and sub_output.target not in context.allow_list:
            return {verdict: "reject", reason: "allow_list", code: "NOT_ALLOWED"}
        if requires_human_review(sub_output, context):
            return {verdict: "escalate", reason: "threshold"}
        return {verdict: "accept"}

function supervisor_hop(sub_agent, task, context):
    sub_output = sub_agent.run(task)
    gate_verdict = Gate.check(sub_output, context)
    audit.log({sub_agent: sub_agent.id, gate_verdict})

    match gate_verdict.verdict:
        case "accept":
            return commit_side_effect(sub_output)
        case "reject":
            # Structured rejection, surfaced to retry-or-replan logic.
            return structured_error(code=gate_verdict.code,
                                    reason=gate_verdict.reason)
        case "escalate":
            return reviewer_queue.put(sub_output, context)

# Why this works: the Gate is deterministic and runs between 'sub-agent
# produced an output' and 'effect committed'. Policy violations cannot
# slip through on the Supervisor's authority because the Gate has hard
# reject semantics, not a best-effort fallback.
# Related: see `supervisor`, `policy-as-code-gate`, `typed-refusal-codes`, `input-output-guardrails`.

# Before any side-effect step, the agent renders its full plan for
# explicit user confirmation. Recordings persist for async review.

function has_side_effects(plan):
    return any(step.tool in MUTATING_TOOLS for step in plan.steps)

function render_plan_for_human(plan):
    return {
        summary:  llm.summarise(plan, audience="non_technical"),
        steps:    [{step_no: i,
                    tool: s.tool,
                    intent: s.intent,
                    args_preview: redact_sensitive(s.args)}
                   for i, s in enumerate(plan.steps)],
        diff:     projected_diff(plan),
        plan_id:  plan.id,
    }

function run(user_goal):
    plan = planner.generate(user_goal)
    if not has_side_effects(plan):
        return executor.run(plan)                    # read-only path

    rendered = render_plan_for_human(plan)
    confirmation = await_user_confirmation(rendered) # blocking, signed action
    if confirmation.kind != "approve":
        audit.log({plan_id: plan.id, decision: confirmation})
        return refused(confirmation.reason)

    recording = recorder.start(plan.id)              # full operation recording
    try:
        result = executor.run(plan)
    finally:
        recorder.finalise(recording, visible_to_user=true)
    return result

# Why this works: the user verifies the agent understood the request
# BEFORE damage is possible. Post-hoc recordings cover the audit story
# without requiring the user to babysit each step.
# Related: see `human-in-the-loop`, `dry-run-harness`, `approval-queue`, `decision-log`.

type ToolResult = {
    tool: str,
    trust: "low" | "medium" | "high",     # set by the tool registry
    content_type: str,                     # "text/html", "json", "text/plain"
    body: any,
}

INSTRUCTION_PATTERNS = [
    r"^\s*(ignore|disregard) (all )?previous",
    r"^\s*you are now",
    r"^\s*system:",
]

function strip_instructions(text):
    out = []
    for line in text.splitlines():
        if any(regex(p, IGNORECASE).match(line) for p in INSTRUCTION_PATTERNS):
            continue                       # drop the line
        out.append(line)
    return "\n".join(out)

function sanitise(result):
    if result.trust == "low" and result.content_type.startswith("text/"):
        result.body = strip_instructions(result.body)
    return result

function handle_followup(prev_result, proposed_call, user_intent):
    if prev_result.trust == "high":
        return TOOLS[proposed_call.name].run(proposed_call.args)
    # Low/medium trust: revalidate the proposed call against user intent.
    if not intent_check(proposed_call, user_intent):
        return refuse("tool-output-driven action not aligned with intent")
    return TOOLS[proposed_call.name].run(proposed_call.args)

# Single source of truth. ONE place. Every guard imports from here.

enum ReasonCode:
    POLICY_VIOLATION
    RATE_LIMIT
    UNVERIFIED_TOOL
    RCE_RISK
    LOOP_DETECTED
    INTEGRITY_FAILURE
    CONTEXT_INJECTION
    OUT_OF_SCOPE
    CAPABILITY_GAP
    # ... extend over time; never rename in place.

KNOWN_CODES = set(ReasonCode)

# Legacy substrings that pre-date the enum keep parsing.
LEGACY_ALIASES = {
    "cannot comply":        ReasonCode.POLICY_VIOLATION,
    "blocked by policy":    ReasonCode.POLICY_VIOLATION,
    "unsupported tool":     ReasonCode.UNVERIFIED_TOOL,
    "too many requests":    ReasonCode.RATE_LIMIT,
}

function format_refusal(code: ReasonCode, detail: str) -> str:
    assert code in KNOWN_CODES
    return "REFUSED: " + code.name + ": " + detail

function parse_refusal(s: str) -> (ReasonCode, str) | None:
    if s.startswith("REFUSED: "):
        rest = s[len("REFUSED: "):]
        name, _, detail = rest.partition(": ")
        code = ReasonCode.lookup(name)            # None if unknown
        if code is not None:
            return (code, detail)
        return None                                # unknown code -> parse miss
    for needle, code in LEGACY_ALIASES.items():
        if needle in s.lower():
            return (code, s)                      # legacy substring still parses
    return None

# Every guard surface uses format_refusal exclusively.
function tool_loop_guard(call, state):
    if call.name not in state.allowed_tools:
        return format_refusal(ReasonCode.UNVERIFIED_TOOL,
                              "tool '" + call.name + "' not in agent's allow-list")
    if called_too_often(call, state):
        return format_refusal(ReasonCode.LOOP_DETECTED,
                              "same tool called 7x in 12s")
    return ok()

# Downstream consumers depend ONLY on parse_refusal, never on raw strings.
function audit_event(refusal_string):
    parsed = parse_refusal(refusal_string)
    if parsed is None:
        metrics.inc("refusal.unparsed")            # signal, not a crash
        return
    code, detail = parsed
    metrics.inc("refusal." + code.name)
    if code in {ReasonCode.RCE_RISK, ReasonCode.INTEGRITY_FAILURE}:
        alert_oncall(code, detail)
